(function(){
"use strict";
const DATA = {"topics": [{"id": "salon_booking", "title": "Hair salon — Book an appointment", "desc": "Book or change a haircut appointment in Saint-Gilles-Croix-de-Vie.", "tags": ["salon", "everyday", "service"], "recommended": 45, "speakPrompt": "Call a hair salon to book an appointment for a haircut and ask about availability.", "dialogue": [["Receptionist", "Good morning, Ocean Hair Salon. How can I help you?", "Bonjour, salon Ocean Hair. Comment puis-je vous aider ?"], ["Candidate", "Good morning. I would like to book an appointment for a haircut, please.", "Bonjour. J'aimerais prendre rendez-vous pour une coupe, s'il vous plaît."], ["Receptionist", "Of course. When would you like to come?", "Bien sûr. Quand souhaitez-vous venir ?"], ["Candidate", "Do you have any availability next Friday morning?", "Avez-vous des disponibilités vendredi matin prochain ?"], ["Receptionist", "Yes, we have an appointment at 10:30.", "Oui, nous avons un rendez-vous à 10h30."], ["Candidate", "That would be perfect. Could you confirm it by text message?", "Ce serait parfait. Pourriez-vous le confirmer par SMS ?"]], "writing": {"subject": "Subject: Hair salon appointment request", "body": "Hello,\n\nI would like to book an appointment for a haircut next Friday morning, if possible.\nCould you please let me know your availability and confirm the time by text message?\n\nThank you very much.\nBest regards,\nKarine"}, "builderModel": ["Good morning. I would like to book an appointment for a haircut, please.", "Do you have any availability next Friday morning?", "Could you please confirm the appointment by text message?"], "quizBank": [["Choose the most polite request:", "You want to book a haircut.", ["I want a haircut now.", "I would like to book an appointment for a haircut, please.", "Cut my hair."], 1, "Polite + clear + professional."], ["Choose the best question:", "You need a time slot.", ["Do you have any availability next Friday morning?", "You are free Friday?", "Give me Friday."], 0, "This is natural and polite."], ["Choose the best closing:", "You need confirmation.", ["Confirm it.", "Could you please confirm the appointment by text message?", "Send SMS."], 1, "This is precise and polite."]], "drills": ["Ask to change the appointment to Thursday.", "Ask how long the haircut will take.", "Ask if you can pay by card."], "models": ["Would it be possible to change the appointment to Thursday?", "How long does the haircut usually take?", "Can I pay by card?"]}, {"id": "salon_complaint_colour", "title": "Hair salon — Polite complaint about colour", "desc": "Explain a colour problem calmly and ask for advice.", "tags": ["salon", "problem", "service"], "recommended": 60, "speakPrompt": "You had your hair coloured, but the colour is too dark. Call the salon and ask for advice politely.", "dialogue": [["Receptionist", "Good afternoon, how can I help you?", "Bonjour, comment puis-je vous aider ?"], ["Candidate", "Hello. I had my hair coloured yesterday, but I’m a little worried about the result.", "Bonjour. J'ai fait une couleur hier, mais je suis un peu inquiète du résultat."], ["Receptionist", "What seems to be the problem?", "Quel semble être le problème ?"], ["Candidate", "The colour is much darker than I expected.", "La couleur est beaucoup plus foncée que prévu."], ["Receptionist", "Would you like to come back so we can have a look?", "Souhaitez-vous revenir pour que nous regardions ?"], ["Candidate", "Yes, please. I would really appreciate that.", "Oui, s'il vous plaît. J'apprécierais beaucoup."]], "writing": {"subject": "Subject: Follow-up after colour appointment", "body": "Hello,\n\nI had my hair coloured yesterday, but the result is darker than I expected.\nWould it be possible to come back so you can have a look and advise me?\n\nThank you for your help.\nBest regards,\Karine"}, "builderModel": ["Hello. I had my hair coloured yesterday, but I am a little worried about the result.", "The colour is much darker than I expected.", "Would it be possible to come back so you can have a look?"], "quizBank": [["Choose the best polite complaint:", "The colour is too dark.", ["This is horrible.", "The colour is much darker than I expected.", "You made a mistake."], 1, "It explains the issue calmly."], ["Choose the best solution request:", "You want the salon to check.", ["Would it be possible to come back so you can have a look?", "Fix it now.", "I hate it."], 0, "Polite and solution-focused."], ["Choose the best phrase:", "You appreciate the help.", ["I would really appreciate that.", "Whatever.", "It is normal."], 0, "Natural and polite."]], "drills": ["Explain the colour is too light.", "Ask for an appointment tomorrow.", "Thank the person for their help."], "models": ["The colour is lighter than I expected.", "Would it be possible to come tomorrow?", "Thank you very much for your help. I really appreciate it."]}, {"id": "salon_products", "title": "Hair salon — Recommend a product", "desc": "Help a customer choose shampoo, conditioner or care product.", "tags": ["salon", "service", "everyday"], "recommended": 45, "speakPrompt": "You help a customer in a hair salon choose a product for dry hair.", "dialogue": [["Customer", "Could you recommend a shampoo for dry hair?", "Pouvez-vous recommander un shampoing pour cheveux secs ?"], ["Candidate", "Of course. This shampoo is very good for dry hair.", "Bien sûr. Ce shampoing est très bon pour les cheveux secs."], ["Customer", "How often should I use it?", "À quelle fréquence dois-je l'utiliser ?"], ["Candidate", "You can use it two or three times a week.", "Vous pouvez l'utiliser deux ou trois fois par semaine."], ["Customer", "How much does it cost?", "Combien coûte-t-il ?"], ["Candidate", "It costs twenty-two euros. Would you like a bag?", "Il coûte vingt-deux euros. Souhaitez-vous un sac ?"]], "writing": {"subject": "Product recommendation", "body": "Hello,\n\nFor dry hair, I recommend this shampoo. You can use it two or three times a week.\nIt is gentle and helps make the hair softer.\n\nBest regards,\nKarine"}, "builderModel": ["Of course. This shampoo is very good for dry hair.", "You can use it two or three times a week.", "It costs twenty-two euros. Would you like a bag?"], "quizBank": [["Choose the best product advice:", "Customer has dry hair.", ["This shampoo is very good for dry hair.", "Take this.", "This is expensive."], 0, "Professional and helpful."], ["Choose the correct frequency:", "How often?", ["two or three times a week", "in the station", "at 22 euros"], 0, "Answers frequency."], ["Choose the polite final question:", "Customer buys product.", ["Would you like a bag?", "Bag?", "You need bag."], 0, "Polite service question."]], "drills": ["Recommend a conditioner for damaged hair.", "Explain the price.", "Explain how often to use the product."], "models": ["This conditioner is good for damaged hair.", "It costs eighteen euros.", "You can use it after every shampoo."]}, {"id": "travel_train_delay", "title": "Travel — Train delay and connection", "desc": "Ask for help when a train is delayed and you may miss a connection.", "tags": ["travel", "problem"], "recommended": 60, "speakPrompt": "Your train is delayed and you are worried you will miss your connection. Ask for options.", "dialogue": [["Customer service", "Good afternoon. How can I help?", "Bonjour. Comment puis-je vous aider ?"], ["Candidate", "Hello. My train is delayed and I’m worried I’ll miss my connection.", "Bonjour. Mon train est en retard et j'ai peur de rater ma correspondance."], ["Customer service", "What is your destination?", "Quelle est votre destination ?"], ["Candidate", "I’m travelling to York with a connection in London.", "Je voyage à York avec une correspondance à Londres."], ["Customer service", "We can rebook you on the next available train.", "Nous pouvons vous replacer sur le prochain train disponible."], ["Candidate", "Thank you. Could you confirm the platform and seat reservation?", "Merci. Pourriez-vous confirmer le quai et la réservation de place ?"]], "writing": {"subject": "Subject: Request for help due to train delay", "body": "Hello,\n\nMy train is delayed and I may miss my connection in London.\nCould you please rebook me on the next available train and confirm the platform and seat reservation?\n\nThank you in advance.\nBest regards,\nKarine"}, "builderModel": ["Hello. My train is delayed and I’m worried I’ll miss my connection.", "I’m travelling to York with a connection in London.", "Could you please rebook me on the next available train?"], "quizBank": [["Choose the clearest problem:", "Your train is late.", ["My train is delayed and I’m worried I’ll miss my connection.", "The train is bad.", "I am not happy."], 0, "Clear, factual and useful."], ["Choose the best request:", "You need another train.", ["Could you please rebook me on the next available train?", "Give me another train.", "I want new ticket."], 0, "Polite + precise."], ["Choose the useful details:", "You need information.", ["Confirm the platform and seat reservation.", "Send me something.", "I don't know."], 0, "Specific details help solve the problem."]], "drills": ["Ask which platform the next train leaves from.", "Ask if your ticket is still valid.", "Ask for the information by email."], "models": ["Could you tell me which platform the next train leaves from?", "Is my ticket still valid for the next train?", "Could you please send me the information by email?"]}, {"id": "hotel_room_problem", "title": "Hotel — Check-in and room problem", "desc": "Check in, ask about breakfast, and request a quieter room.", "tags": ["hotel", "problem", "travel"], "recommended": 60, "speakPrompt": "You arrive at a hotel. Check in, ask about breakfast, then say the room is noisy.", "dialogue": [["Receptionist", "Good evening. Do you have a reservation?", "Bonsoir. Avez-vous une réservation ?"], ["Candidate", "Yes, I have a reservation under the name Cormier.", "Oui, j'ai une réservation au nom de Cormier."], ["Receptionist", "Breakfast is from seven to ten.", "Le petit-déjeuner est de 7h à 10h."], ["Candidate", "Thank you. Is breakfast included in the price?", "Merci. Le petit-déjeuner est-il inclus dans le prix ?"], ["Receptionist", "Yes, it is included.", "Oui, il est inclus."], ["Candidate", "Also, my room is quite noisy. Would it be possible to have a quieter room?", "Aussi, ma chambre est assez bruyante. Serait-il possible d'avoir une chambre plus calme ?"]], "writing": {"subject": "Subject: Request for a quieter room", "body": "Hello,\n\nI am staying in room [number]. Unfortunately, the room is quite noisy.\nWould it be possible to move to a quieter room, if available?\n\nThank you very much for your help.\nBest regards,\nKarine"}, "builderModel": ["Hello, I have a reservation under the name Cormier.", "Is breakfast included in the price?", "Would it be possible to have a quieter room?"], "quizBank": [["Choose the best check-in sentence:", "You arrive at the hotel.", ["I have a reservation under the name Cormier.", "Give me room.", "I am here."], 0, "This is clear and standard."], ["Choose the best breakfast question:", "You want to know if it is included.", ["Is breakfast included in the price?", "Breakfast?", "Give breakfast."], 0, "Correct and polite."], ["Choose the polite room request:", "The room is noisy.", ["Would it be possible to have a quieter room?", "This room is terrible.", "I need another room now."], 0, "Polite and solution-focused."]], "drills": ["Ask if there is a lift.", "Ask what time check-out is.", "Ask if the hotel can call a taxi."], "models": ["Is there a lift in the hotel?", "What time is check-out?", "Could you please call a taxi for me?"]}, {"id": "restaurant_allergy", "title": "Restaurant — Book a table and mention allergy", "desc": "Reserve a table and explain a dietary restriction.", "tags": ["restaurant", "travel"], "recommended": 45, "speakPrompt": "Call a restaurant, book a table and mention a nut allergy.", "dialogue": [["Restaurant", "Good evening, how can I help you?", "Bonsoir, comment puis-je vous aider ?"], ["Candidate", "Good evening. I’d like to book a table for two, please.", "Bonsoir. J'aimerais réserver une table pour deux, s'il vous plaît."], ["Restaurant", "For what day and time?", "Pour quel jour et quelle heure ?"], ["Candidate", "For Saturday at 7:30, if possible.", "Pour samedi à 19h30, si possible."], ["Restaurant", "Yes, we have availability.", "Oui, nous avons de la disponibilité."], ["Candidate", "Great. One person has a nut allergy. Is that okay?", "Très bien. Une personne a une allergie aux fruits à coque. Est-ce possible ?"]], "writing": {"subject": "Subject: Table reservation for Saturday", "body": "Hello,\n\nI would like to book a table for two people on Saturday at 7:30 pm.\nPlease note that one person has a nut allergy.\nCould you please confirm the reservation?\n\nThank you very much.\nBest regards,\nKarine"}, "builderModel": ["Good evening. I’d like to book a table for two, please.", "For Saturday at 7:30, if possible.", "One person has a nut allergy. Is that okay?"], "quizBank": [["Choose the best request:", "You want a table.", ["I’d like to book a table for two, please.", "Give me a table.", "We come Saturday."], 0, "Polite and natural."], ["Choose the allergy phrase:", "You need to inform the restaurant.", ["One person has a nut allergy.", "We don't eat.", "There is a problem."], 0, "Clear and safe."], ["Choose the best confirmation request:", "You finish the booking.", ["Could you confirm the reservation?", "Okay bye.", "Remember."], 0, "Professional and useful."]], "drills": ["Ask for a table near the window.", "Ask if vegetarian dishes are available.", "Ask for the bill politely."], "models": ["Could we have a table near the window, please?", "Do you have vegetarian dishes?", "Could we have the bill, please?"]}, {"id": "restaurant_complaint", "title": "Restaurant — Polite complaint about a dish", "desc": "Explain a dish problem calmly and ask for a solution.", "tags": ["restaurant", "problem", "service"], "recommended": 60, "speakPrompt": "Your dish is not what you ordered. Explain the problem and ask for a solution politely.", "dialogue": [["Waiter", "Is everything okay with your meal?", "Tout va bien avec votre repas ?"], ["Candidate", "Thank you. Actually, there is a small problem with my dish.", "Merci. En fait, il y a un petit problème avec mon plat."], ["Waiter", "What seems to be the issue?", "Quel est le problème ?"], ["Candidate", "I ordered the vegetarian pasta, but this one has chicken.", "J'ai commandé les pâtes végétariennes, mais celles-ci ont du poulet."], ["Waiter", "I’m sorry about that. Would you like us to replace it?", "Je suis désolé. Voulez-vous que nous le remplacions ?"], ["Candidate", "Yes, please. Could you remake the vegetarian version?", "Oui, s'il vous plaît. Pourriez-vous refaire la version végétarienne ?"]], "writing": {"subject": "Subject: Feedback about an order mix-up", "body": "Hello,\n\nI visited your restaurant on [date]. The service was friendly, but there was a mix-up with my order.\nI ordered a vegetarian dish, but it arrived with chicken.\nThe team handled it quickly, and I appreciated the solution.\n\nBest regards,\nKarine"}, "builderModel": ["Actually, there is a small problem with my dish.", "I ordered the vegetarian pasta, but this one has chicken.", "Could you remake the vegetarian version, please?"], "quizBank": [["Choose the best tone:", "You want to complain politely.", ["There is a small problem with my dish.", "This is terrible.", "You are incompetent."], 0, "Soft and polite."], ["Choose the clearest explanation:", "What went wrong?", ["I ordered vegetarian, but it has chicken.", "This is not good.", "Fix it."], 0, "Clear and factual."], ["Choose the best request:", "You want a solution.", ["Could you remake the vegetarian version, please?", "Do something.", "Take it away."], 0, "Polite + specific."]], "drills": ["Say the soup is cold.", "Ask if the dish contains nuts.", "Thank the waiter for replacing the dish."], "models": ["The soup is a little cold. Could you warm it up, please?", "Does this dish contain nuts?", "Thank you very much for replacing the dish. I appreciate it."]}, {"id": "directions_city", "title": "Everyday travel — Ask for directions", "desc": "Ask for directions to a tourist office, museum or station.", "tags": ["everyday", "travel"], "recommended": 45, "speakPrompt": "You are in a UK city and need directions to the tourist office.", "dialogue": [["Local person", "Hello, can I help you?", "Bonjour, puis-je vous aider ?"], ["Candidate", "Yes, please. I’m looking for the tourist office.", "Oui, s'il vous plaît. Je cherche l'office de tourisme."], ["Local person", "It’s near the museum, about five minutes from here.", "C'est près du musée, à environ cinq minutes d'ici."], ["Candidate", "Could you tell me how to get there?", "Pourriez-vous me dire comment y aller ?"], ["Local person", "Go straight ahead, then turn left at the traffic lights.", "Allez tout droit, puis tournez à gauche au feu."], ["Candidate", "Great, thank you for your help.", "Très bien, merci pour votre aide."]], "writing": {"subject": "Short note: Directions", "body": "Hello,\n\nI am looking for the tourist office. Could you please tell me how to get there from the station?\n\nThank you for your help.\nKarine"}, "builderModel": ["Excuse me. I’m looking for the tourist office.", "Could you tell me how to get there?", "Thank you very much for your help."], "quizBank": [["Choose the best opening:", "You need directions.", ["Excuse me. I’m looking for the tourist office.", "Where office?", "You tell me."], 0, "Polite and clear."], ["Choose the best question:", "You need instructions.", ["Could you tell me how to get there?", "Go there?", "Where?"], 0, "Natural phrase."], ["Choose the best closing:", "You want to thank the person.", ["Thank you very much for your help.", "Ok.", "Fine."], 0, "Polite closing."]], "drills": ["Ask if the museum is far.", "Ask where the bus stop is.", "Repeat the directions to check."], "models": ["Is the museum far from here?", "Could you tell me where the bus stop is?", "So I go straight ahead and turn left, is that correct?"]}, {"id": "phone_reschedule", "title": "Everyday — Reschedule an appointment", "desc": "Change an appointment politely by phone or email.", "tags": ["everyday", "problem", "service"], "recommended": 45, "speakPrompt": "You need to reschedule an appointment because you are not available.", "dialogue": [["Assistant", "Good morning. How can I help?", "Bonjour. Comment puis-je vous aider ?"], ["Candidate", "Good morning. I’m calling to reschedule my appointment.", "Bonjour. J'appelle pour reprogrammer mon rendez-vous."], ["Assistant", "What day is your appointment?", "Quel jour est votre rendez-vous ?"], ["Candidate", "It is on Tuesday at 10 am.", "Il est mardi à 10h."], ["Assistant", "When would you like to reschedule?", "Quand souhaitez-vous le reprogrammer ?"], ["Candidate", "Would Thursday afternoon be possible?", "Jeudi après-midi serait-il possible ?"]], "writing": {"subject": "Subject: Request to reschedule appointment", "body": "Hello,\n\nI am writing to reschedule my appointment on Tuesday at 10 am.\nWould Thursday afternoon be possible?\n\nThank you for your understanding.\nBest regards,\nKarine"}, "builderModel": ["Good morning. I’m calling to reschedule my appointment.", "Would Thursday afternoon be possible?", "Perfect, thank you. I confirm Thursday at 3 pm."], "quizBank": [["Choose the best phrase:", "You need a new time.", ["I’m calling to reschedule my appointment.", "I cancel everything.", "I can't."], 0, "Clear purpose."], ["Choose the polite question:", "Suggest another time.", ["Would Thursday afternoon be possible?", "Thursday now.", "I want Thursday."], 0, "Polite."], ["Choose the confirmation:", "You accept the new time.", ["I confirm Thursday at 3 pm.", "Maybe.", "Ok thing."], 0, "Clear confirmation."]], "drills": ["Apologize for the inconvenience.", "Suggest Monday morning.", "Ask for confirmation by email."], "models": ["I apologize for the inconvenience.", "Would Monday morning be possible instead?", "Could you please confirm the new appointment by email?"]}, {"id": "weather_plans", "title": "Travel — Weather and activity choice", "desc": "Change plans because of weather and explain alternatives.", "tags": ["travel", "everyday"], "recommended": 45, "speakPrompt": "It is rainy during your trip. Explain what you are going to do instead.", "dialogue": [["Friend", "What are you going to do today?", "Qu'allez-vous faire aujourd'hui ?"], ["Candidate", "I was going to go hiking, but it is raining.", "Je comptais faire de la randonnée, mais il pleut."], ["Friend", "What will you do instead?", "Que ferez-vous à la place ?"], ["Candidate", "I think I’ll visit a museum because it is indoors.", "Je pense que je visiterai un musée parce que c'est à l'intérieur."], ["Friend", "That sounds like a good idea.", "Ça semble être une bonne idée."], ["Candidate", "Yes, it is more comfortable than walking in the rain.", "Oui, c'est plus confortable que marcher sous la pluie."]], "writing": {"subject": "Change of plans because of the weather", "body": "Hello,\n\nBecause it is raining today, I am going to change my plans.\nInstead of hiking, I am going to visit a museum because it is indoors and more comfortable.\n\nBest regards,\nKarine"}, "builderModel": ["I was going to go hiking, but it is raining.", "I think I’ll visit a museum because it is indoors.", "It is more comfortable than walking in the rain."], "quizBank": [["Choose the best connector:", "You change plans.", ["but", "and", "because"], 0, "But introduces contrast."], ["Choose the best reason:", "Why museum?", ["because it is indoors", "because train", "because hair"], 0, "Correct reason."], ["Choose the comparative:", "Museum vs rain.", ["more comfortable than", "comfortable more", "the comfortable"], 0, "Correct comparative form."]], "drills": ["Say it is too windy for a boat trip.", "Suggest a café instead.", "Explain why a museum is better."], "models": ["It is too windy for a boat trip.", "We could go to a café instead.", "A museum is better because it is indoors and more comfortable."]}, {"id": "compare_hotels", "title": "Travel — Compare hotels and destinations", "desc": "Use comparatives and superlatives to choose the best option.", "tags": ["travel", "hotel"], "recommended": 60, "speakPrompt": "Compare two hotels and explain which one is better for you.", "dialogue": [["Travel agent", "Which hotel do you prefer?", "Quel hôtel préférez-vous ?"], ["Candidate", "I prefer the second hotel because it is quieter.", "Je préfère le deuxième hôtel parce qu'il est plus calme."], ["Travel agent", "Is it more expensive?", "Est-il plus cher ?"], ["Candidate", "Yes, it is a little more expensive, but it is closer to the station.", "Oui, il est un peu plus cher, mais il est plus proche de la gare."], ["Travel agent", "What is the most important point for you?", "Quel est le point le plus important pour vous ?"], ["Candidate", "The most important point is location.", "Le point le plus important est l'emplacement."]], "writing": {"subject": "Hotel comparison", "body": "Hello,\n\nI prefer the second hotel because it is quieter and closer to the station.\nIt is a little more expensive, but the location is better for me.\nI think it is the best option.\n\nBest regards,\nKarine"}, "builderModel": ["I prefer the second hotel because it is quieter.", "It is more expensive, but it is closer to the station.", "I think it is the best option for me."], "quizBank": [["Choose the correct comparative:", "Quiet hotel.", ["quieter", "more quietest", "quiet"], 0, "Short adjective: quiet → quieter."], ["Choose the correct superlative:", "Best option.", ["the best option", "the better option", "best option"], 0, "Use THE with superlative."], ["Choose the connector:", "Contrasting price/location.", ["but", "because", "first"], 0, "But introduces contrast."]], "drills": ["Compare two restaurants.", "Say Bath is more relaxing than London.", "Say Edinburgh is the most interesting option."], "models": ["The first restaurant is cheaper, but the second one is quieter.", "Bath is more relaxing than London.", "Edinburgh is the most interesting option for me."]}, {"id": "lost_luggage", "title": "Travel — Lost luggage at the airport", "desc": "Report missing luggage and give clear details.", "tags": ["travel", "problem", "service"], "recommended": 60, "speakPrompt": "Your luggage has not arrived at the airport. Report the problem and ask what to do next.", "dialogue": [["Staff", "Hello. How can I help you?", "Bonjour. Comment puis-je vous aider ?"], ["Candidate", "Hello. My suitcase has not arrived.", "Bonjour. Ma valise n'est pas arrivée."], ["Staff", "Can you describe it?", "Pouvez-vous la décrire ?"], ["Candidate", "It is a medium black suitcase with a red tag.", "C'est une valise noire moyenne avec une étiquette rouge."], ["Staff", "Do you have your baggage receipt?", "Avez-vous votre reçu de bagage ?"], ["Candidate", "Yes, here it is. Could you tell me what I should do next?", "Oui, le voici. Pourriez-vous me dire ce que je dois faire ensuite ?"]], "writing": {"subject": "Subject: Lost luggage report", "body": "Hello,\n\nMy suitcase did not arrive after my flight. It is a medium black suitcase with a red tag.\nCould you please let me know what I should do next and how I can be contacted?\n\nBest regards,\nKarine"}, "builderModel": ["Hello. My suitcase has not arrived.", "It is a medium black suitcase with a red tag.", "Could you tell me what I should do next?"], "quizBank": [["Choose the clearest description:", "Describe the suitcase.", ["It is a medium black suitcase with a red tag.", "It is normal.", "It is mine."], 0, "Specific and useful."], ["Choose the useful document:", "Staff asks for proof.", ["baggage receipt", "restaurant bill", "haircut appointment"], 0, "Correct travel document."], ["Choose the next-step question:", "You need help.", ["Could you tell me what I should do next?", "Where is it?", "This is bad."], 0, "Polite and practical."]], "drills": ["Describe a blue suitcase.", "Ask when it will be delivered.", "Give your hotel address."], "models": ["It is a large blue suitcase with a grey handle.", "When will it be delivered?", "I am staying at the Royal Hotel in York."]}, {"id": "taxi_hotel", "title": "Travel — Taxi to hotel", "desc": "Give destination, ask price and confirm payment method.", "tags": ["travel", "everyday", "service"], "recommended": 45, "speakPrompt": "Take a taxi from the station to your hotel. Ask about the price and card payment.", "dialogue": [["Driver", "Good afternoon. Where would you like to go?", "Bonjour. Où souhaitez-vous aller ?"], ["Candidate", "Good afternoon. I would like to go to the Royal Hotel, please.", "Bonjour. Je voudrais aller au Royal Hotel, s'il vous plaît."], ["Driver", "Of course. It takes about fifteen minutes.", "Bien sûr. Cela prend environ quinze minutes."], ["Candidate", "Could you tell me approximately how much it will cost?", "Pourriez-vous me dire environ combien cela coûtera ?"], ["Driver", "About twelve pounds.", "Environ douze livres."], ["Candidate", "Thank you. Can I pay by card?", "Merci. Puis-je payer par carte ?"]], "writing": {"subject": "Taxi request note", "body": "Hello,\n\nI would like to go to the Royal Hotel from the station.\nCould you please tell me the approximate price, and can I pay by card?\n\nThank you.\nKarine"}, "builderModel": ["I would like to go to the Royal Hotel, please.", "Could you tell me approximately how much it will cost?", "Can I pay by card?"], "quizBank": [["Choose the destination phrase:", "Tell the driver where to go.", ["I would like to go to the Royal Hotel, please.", "Go hotel.", "Royal."], 0, "Polite and complete."], ["Choose the price question:", "Ask the approximate price.", ["Could you tell me approximately how much it will cost?", "How money?", "You cost?"], 0, "Natural and polite."], ["Choose the payment question:", "Ask about card.", ["Can I pay by card?", "Card yes?", "I have card."], 0, "Simple and correct."]], "drills": ["Ask the driver to stop here.", "Ask for a receipt.", "Say you are in a hurry."], "models": ["Could you stop here, please?", "Could I have a receipt, please?", "I am in a hurry. How long will it take?"]}, {"id": "tourist_info", "title": "Travel — Tourist office recommendations", "desc": "Ask for recommendations, opening hours and maps.", "tags": ["travel", "everyday", "service"], "recommended": 45, "speakPrompt": "At the tourist office, ask for recommendations for a rainy day.", "dialogue": [["Agent", "Hello. How can I help you?", "Bonjour. Comment puis-je vous aider ?"], ["Candidate", "Hello. Could you recommend an activity for a rainy day?", "Bonjour. Pourriez-vous recommander une activité pour un jour de pluie ?"], ["Agent", "You could visit the city museum.", "Vous pourriez visiter le musée de la ville."], ["Candidate", "That sounds interesting. What time does it open?", "Cela semble intéressant. À quelle heure ouvre-t-il ?"], ["Agent", "It opens at ten and closes at five.", "Il ouvre à dix heures et ferme à cinq heures."], ["Candidate", "Great. Could I have a map, please?", "Très bien. Pourrais-je avoir un plan, s'il vous plaît ?"]], "writing": {"subject": "Tourist office request", "body": "Hello,\n\nCould you recommend activities for a rainy day in the city?\nI would also like information about opening hours and a city map.\n\nThank you.\nKarine"}, "builderModel": ["Could you recommend an activity for a rainy day?", "What time does the museum open?", "Could I have a map, please?"], "quizBank": [["Choose the recommendation request:", "Rainy day.", ["Could you recommend an activity for a rainy day?", "What rainy?", "Give activity."], 0, "Polite and specific."], ["Choose the opening hours question:", "Ask about time.", ["What time does it open?", "When open it?", "It opens?"], 0, "Correct question order."], ["Choose the map request:", "Ask for map.", ["Could I have a map, please?", "Map me.", "I need map."], 0, "Polite and complete."]], "drills": ["Ask for a walking tour.", "Ask if the museum is free.", "Ask how to get to the castle."], "models": ["Do you have a walking tour today?", "Is the museum free?", "Could you tell me how to get to the castle?"]}, {"id": "doctor_pharmacy", "title": "Everyday travel — Pharmacy advice", "desc": "Ask for medicine or advice while travelling.", "tags": ["everyday", "travel", "service"], "recommended": 45, "speakPrompt": "You are at a pharmacy in the UK. Ask for something for a headache and explain symptoms simply.", "dialogue": [["Pharmacist", "Hello. How can I help you?", "Bonjour. Comment puis-je vous aider ?"], ["Candidate", "Hello. I have a headache. Do you have something for pain?", "Bonjour. J'ai mal à la tête. Avez-vous quelque chose contre la douleur ?"], ["Pharmacist", "Do you have any allergies?", "Avez-vous des allergies ?"], ["Candidate", "No, I don’t have any allergies.", "Non, je n'ai pas d'allergies."], ["Pharmacist", "You can take this after food.", "Vous pouvez prendre ceci après avoir mangé."], ["Candidate", "Thank you. How often should I take it?", "Merci. À quelle fréquence dois-je le prendre ?"]], "writing": {"subject": "Pharmacy request", "body": "Hello,\n\nI have a headache and I would like something for pain.\nI do not have any allergies. Could you please tell me how often I should take it?\n\nThank you.\nKarine"}, "builderModel": ["Hello. I have a headache.", "Do you have something for pain?", "How often should I take it?"], "quizBank": [["Choose the symptom phrase:", "Headache.", ["I have a headache.", "I am headache.", "My head is travel."], 0, "Correct health phrase."], ["Choose the allergy answer:", "No allergies.", ["No, I don’t have any allergies.", "No allergic.", "Nothing."], 0, "Clear and safe."], ["Choose the dosage question:", "How often?", ["How often should I take it?", "When eat?", "How much repeat?"], 0, "Correct question."]], "drills": ["Say you have a sore throat.", "Ask if it makes you sleepy.", "Ask how much it costs."], "models": ["I have a sore throat.", "Does it make you sleepy?", "How much does it cost?"]}, {"id": "smalltalk_travel", "title": "CLOE small talk — Introduce yourself and travel", "desc": "Talk about yourself, hobbies, family and travel naturally.", "tags": ["everyday", "travel"], "recommended": 60, "speakPrompt": "Introduce yourself and explain why English is important for you.", "dialogue": [["Examiner", "Could you introduce yourself?", "Pouvez-vous vous présenter ?"], ["Candidate", "Hello, my name is Karine. I’m from France and I live in Nantes.", "Bonjour, je m'appelle Karine. Je viens de France et j'habite à Nantes."], ["Examiner", "Why is English important for you?", "Pourquoi l'anglais est-il important pour vous ?"], ["Candidate", "English is important because I need it when I travel abroad.", "L'anglais est important parce que j'en ai besoin quand je voyage à l'étranger."], ["Examiner", "What do you enjoy doing?", "Qu'aimez-vous faire ?"], ["Candidate", "I enjoy African dance, African percussion and travelling.", "J'aime la danse africaine, les percussions africaines et voyager."]], "writing": {"subject": "Self-introduction", "body": "Hello,\n\nMy name is Karine. I am from France and I live in Nantes. I am retired now. English is important for me because I need it when I travel abroad. In my free time, I enjoy African dance, African percussion and travelling.\n\nNice to meet you."}, "builderModel": ["Hello, my name is Karine. I am from France and I live in Nantes.", "English is important for me because I need it when I travel abroad.", "In my free time, I enjoy African dance, African percussion and travelling."], "quizBank": [["Choose the best introduction:", "Start speaking.", ["Hello, my name is Karine.", "Me Karine.", "I have Karine."], 0, "Correct introduction."], ["Choose the reason:", "Why English?", ["because I need it when I travel abroad", "because yes", "for travel English important"], 0, "Clear reason."], ["Choose the hobby sentence:", "Talk about hobbies.", ["I enjoy African dance and travelling.", "I enjoy to African dance.", "I am enjoy travel."], 0, "Correct after enjoy: verb-ing/noun."]], "drills": ["Say where you live.", "Say your goal for the course.", "Say your favourite trip was Scotland."], "models": ["I live in Nantes.", "My goal is to feel more comfortable speaking English.", "My favourite trip was Scotland."]}], "grammar": [{"id": "present", "title": "Present Simple vs Present Continuous", "rule": "Present Simple = habits, facts, schedules. Present Continuous = now / today / temporary action.", "examples": ["I usually travel by train.", "I am travelling to York today.", "The salon opens at 9 am.", "I am looking for the tourist office."], "ex": [["I usually ___ by train.", "travel", ["travel", "am travelling", "travels"]], ["Today I ___ to York.", "am travelling", ["travel", "am travelling", "travels"]], ["The salon ___ at 9 am.", "opens", ["open", "opens", "is opening"]], ["I ___ for the station now.", "am looking", ["look", "am looking", "looks"]], ["She usually ___ customers on Friday.", "helps", ["help", "helps", "is helping"]], ["At the moment, she ___ a customer.", "is helping", ["helps", "is helping", "help"]]]}, {"id": "past", "title": "Past Simple vs Present Perfect", "rule": "Past Simple = finished time. Present Perfect = life experience/result now without exact past time.", "examples": ["I visited Scotland last year.", "I have travelled to Asia.", "I studied in Paris.", "I have booked a hotel."], "ex": [["I ___ Scotland last year.", "visited", ["visited", "have visited", "visit"]], ["I ___ to Asia.", "have travelled", ["travelled yesterday", "have travelled", "travel"]], ["I ___ in Paris when I was younger.", "studied", ["studied", "have studied", "study"]], ["I ___ a hotel for tonight.", "have booked", ["booked last week", "have booked", "book"]], ["Yesterday, I ___ the salon.", "called", ["called", "have called", "call"]], ["I ___ many places in France.", "have visited", ["visited yesterday", "have visited", "visit"]]]}, {"id": "future", "title": "Future: Going to / Will", "rule": "Going to = plan/intention. Will = decision now / prediction / offer.", "examples": ["I am going to visit Guadeloupe in December.", "I will call the hotel now.", "I think it will rain.", "I will help you."], "ex": [["I ___ visit Guadeloupe in December.", "am going to", ["am going to", "will to", "going"]], ["The phone is ringing. I ___ answer it.", "will", ["am going to", "will", "do"]], ["She ___ book a hotel next week.", "is going to", ["is going to", "will to", "does"]], ["I think it ___ rain tomorrow.", "will", ["will", "is going to", "does"]], ["We ___ take the train. We already bought the tickets.", "are going to", ["are going to", "will", "do"]], ["I forgot to confirm. I ___ do it now.", "will", ["will", "am going to", "did"]]]}, {"id": "questions", "title": "Negatives and Questions", "rule": "Use do/does/did for present/past simple questions and negatives. Use BE first for BE structures.", "examples": ["Do you travel often?", "Does she work in the salon?", "Did you visit York?", "Are you waiting for the train?"], "ex": [["___ you travel often?", "Do", ["Do", "Are", "Does"]], ["___ she work in the salon?", "Does", ["Do", "Does", "Is"]], ["___ you visit York last year?", "Did", ["Do", "Did", "Are"]], ["___ you waiting for the train?", "Are", ["Do", "Are", "Did"]], ["I ___ speak German.", "do not", ["am not", "do not", "does not"]], ["She ___ travel every weekend.", "does not", ["do not", "is not", "does not"]]]}, {"id": "articles", "title": "Articles: A / AN / THE / Ø", "rule": "A/AN = one thing first mention. THE = specific/known. Ø = no article for languages, countries, activities in general.", "examples": ["I need a hotel.", "I booked an apartment.", "The hotel is near the station.", "I speak English. I live in France. I like travelling."], "ex": [["I need ___ hotel.", "a", ["a", "an", "the", "Ø"]], ["I booked ___ apartment.", "an", ["a", "an", "the", "Ø"]], ["___ hotel is near the station.", "The", ["A", "An", "The", "Ø"]], ["I speak ___ English.", "Ø", ["a", "an", "the", "Ø"]], ["I enjoy ___ African dance.", "Ø", ["a", "an", "the", "Ø"]], ["Could I have ___ receipt?", "a", ["a", "an", "the", "Ø"]]]}, {"id": "prepositions", "title": "Prepositions + Verb Blocks", "rule": "Use at for points, in for enclosed places, on for public transport, by for travel method. Learn verb blocks: look for, talk about, wait for, travel with.", "examples": ["I am at the station.", "I am in a taxi.", "I am on the train.", "I travel by plane.", "What are you looking for?"], "ex": [["I am ___ the station.", "at", ["at", "in", "by"]], ["I am ___ a taxi.", "in", ["on", "in", "by"]], ["I am ___ the train.", "on", ["on", "in", "by"]], ["What are you looking ___?", "for", ["for", "about", "with"]], ["Who are you travelling ___?", "with", ["for", "with", "about"]], ["What are you talking ___?", "about", ["for", "about", "at"]]]}, {"id": "connectors", "title": "Sequencing and Connectors", "rule": "Use sequencing to organize a story: first, then, after that, finally. Use connectors for logic: because, but, so, however.", "examples": ["First, I check in. Then, I go to my room.", "I chose the hotel because it is quiet.", "It is expensive, but it is comfortable.", "It was raining, so I visited a museum."], "ex": [["___, I check in at the hotel.", "First", ["First", "Because", "But"]], ["I chose the hotel ___ it is quiet.", "because", ["because", "but", "finally"]], ["It is expensive, ___ it is comfortable.", "but", ["so", "but", "first"]], ["It was raining, ___ I visited a museum.", "so", ["so", "but", "however"]], ["___ that, I went to the station.", "After", ["After", "Because", "But"]], ["I like the hotel. ___, it is a little expensive.", "However", ["However", "Because", "First"]]]}, {"id": "adjectives", "title": "Adjectives and Adverbs", "rule": "Adjectives describe nouns. Adverbs describe verbs/actions. Many adverbs end in -ly.", "examples": ["The room is quiet.", "She speaks slowly.", "It is a comfortable hotel.", "He answers politely."], "ex": [["The room is ___.", "quiet", ["quiet", "quietly", "slowly"]], ["She speaks ___.", "slowly", ["slow", "slowly", "quiet"]], ["It is a ___ hotel.", "comfortable", ["comfortably", "comfortable", "slowly"]], ["He answers ___.", "politely", ["polite", "politely", "quiet"]], ["The stylist is ___.", "professional", ["professionally", "professional", "quickly"]], ["She works ___.", "carefully", ["careful", "carefully", "comfortable"]]]}, {"id": "comparison", "title": "Comparatives and Superlatives", "rule": "Comparative = compare two things. Superlative = the top one. Use -er for short adjectives, more for long adjectives, the most / the best for superlatives.", "examples": ["This hotel is quieter than the first one.", "It is more expensive.", "It is the best option.", "York is the most interesting city for me."], "ex": [["This hotel is ___ than the first one.", "quieter", ["quieter", "quietest", "quiet"]], ["It is ___ expensive.", "more", ["more", "most", "the"]], ["It is ___ best option.", "the", ["a", "the", "Ø"]], ["This is the ___ interesting city.", "most", ["more", "most", "better"]], ["This salon is ___ than the other one.", "better", ["best", "better", "good"]], ["It is the ___ comfortable hotel.", "most", ["more", "most", "better"]]]}, {"id": "modals", "title": "Polite Modals: Can / Could / Would", "rule": "Use can for simple ability/request, could for polite request, would like for formal/polite wishes.", "examples": ["Can I pay by card?", "Could you repeat that please?", "I would like a quiet room.", "Would it be possible to change the appointment?"], "ex": [["___ you repeat that please?", "Could", ["Do", "Could", "Are"]], ["I ___ like a quiet room.", "would", ["do", "would", "am"]], ["___ it be possible to change the time?", "Would", ["Do", "Would", "Can"]], ["Can I ___ by card?", "pay", ["pay", "paying", "paid"]], ["Could you ___ me?", "help", ["help", "helps", "helping"]], ["I would like ___ appointment.", "an", ["a", "an", "the"]]]}], "vocab": [["travel", "🚆", "train delay", "retard de train", "The train is delayed."], ["travel", "🔗", "connection", "correspondance", "I may miss my connection."], ["travel", "🎫", "return ticket", "billet aller-retour", "I would like a return ticket."], ["travel", "🚉", "platform", "quai", "The train leaves from platform four."], ["travel", "🧳", "luggage", "bagages", "I am looking for my luggage."], ["travel", "🧾", "baggage receipt", "reçu bagage", "Do you have your baggage receipt?"], ["travel", "🚕", "taxi rank", "station de taxis", "Where is the taxi rank?"], ["travel", "📍", "tourist office", "office de tourisme", "I am looking for the tourist office."], ["hotel", "🏨", "reservation", "réservation", "I have a reservation under the name Cormier."], ["hotel", "🥐", "breakfast included", "petit-déjeuner inclus", "Is breakfast included?"], ["hotel", "🔊", "noisy", "bruyant", "The room is noisy."], ["hotel", "🤫", "quieter room", "chambre plus calme", "Could I have a quieter room?"], ["hotel", "🛗", "lift", "ascenseur", "Is there a lift?"], ["hotel", "🕚", "check-out", "départ hôtel", "What time is check-out?"], ["hotel", "🛏️", "double room", "chambre double", "I booked a double room."], ["hotel", "🧾", "receipt", "reçu", "Could I have a receipt?"], ["restaurant", "🍽️", "book a table", "réserver une table", "I would like to book a table."], ["restaurant", "🥜", "nut allergy", "allergie aux noix", "One person has a nut allergy."], ["restaurant", "🧾", "bill", "addition", "Could we have the bill?"], ["restaurant", "💳", "pay by card", "payer par carte", "Can I pay by card?"], ["restaurant", "🥗", "vegetarian", "végétarien", "I ordered the vegetarian pasta."], ["restaurant", "🔁", "replace", "remplacer", "Could you replace it?"], ["restaurant", "🍝", "dish", "plat", "There is a problem with my dish."], ["salon", "💇", "haircut", "coupe de cheveux", "I would like a haircut."], ["salon", "📅", "appointment", "rendez-vous", "I would like to book an appointment."], ["salon", "✅", "availability", "disponibilité", "Do you have any availability?"], ["salon", "🎨", "colour", "couleur", "The colour is darker than expected."], ["salon", "🧴", "shampoo", "shampoing", "This shampoo is good for dry hair."], ["salon", "💁", "stylist", "coiffeur / coiffeuse", "The stylist is very professional."], ["salon", "💆", "conditioner", "après-shampoing", "This conditioner is good for damaged hair."], ["salon", "✂️", "trim", "couper les pointes", "I would like a small trim."], ["service", "🙏", "I’m sorry to bother you", "désolé(e) de vous déranger", "I’m sorry to bother you, but there is a problem."], ["service", "📩", "confirm by email", "confirmer par mail", "Could you confirm by email?"], ["service", "📱", "text message", "SMS", "Could you confirm by text message?"], ["service", "❓", "Would it be possible...?", "Serait-il possible... ?", "Would it be possible to change the time?"], ["service", "✅", "I appreciate it", "j'apprécie", "Thank you, I appreciate it."], ["problem", "🔁", "reschedule", "reprogrammer", "I need to reschedule my appointment."], ["problem", "🛠️", "solution", "solution", "Could you offer a solution?"], ["problem", "⚠️", "issue", "problème", "There is an issue with my room."], ["problem", "😟", "worried", "inquiet/inquiète", "I am worried about the result."], ["problem", "🔍", "have a look", "regarder", "Could you have a look?"], ["grammar", "🗣️", "I would like...", "Je voudrais...", "I would like a quiet room."], ["grammar", "🔍", "I am looking for...", "Je cherche...", "I am looking for the station."], ["grammar", "💬", "What are you talking about?", "De quoi parlez-vous ?", "What are you talking about?"], ["grammar", "👥", "I am travelling with...", "Je voyage avec...", "I am travelling with my family."], ["connectors", "➡️", "first", "d'abord", "First, I check in."], ["connectors", "➡️", "then", "ensuite", "Then, I go to my room."], ["connectors", "🔚", "finally", "enfin", "Finally, I visit the museum."], ["connectors", "🔗", "because", "parce que", "I chose it because it is quiet."], ["connectors", "⚖️", "but", "mais", "It is expensive but comfortable."], ["connectors", "✅", "so", "donc", "It was raining, so I visited a museum."], ["connectors", "🔄", "however", "cependant", "However, it is a little expensive."], ["opinions", "😊", "I prefer", "je préfère", "I prefer the second hotel."], ["opinions", "⭐", "the best option", "la meilleure option", "It is the best option for me."], ["opinions", "👍", "I recommend", "je recommande", "I recommend this shampoo."], ["opinions", "💭", "I think", "je pense", "I think it is more comfortable."]], "listenings": [{"title": "Hotel check-in", "audio": "Good evening. I have a reservation under the name Cormier. Is breakfast included in the price? Also, my room is quite noisy. Would it be possible to have a quieter room?", "transcript": "Good evening. I have a reservation under the name Cormier. Is breakfast included in the price? Also, my room is quite noisy. Would it be possible to have a quieter room?", "q": "What problem does the speaker mention?", "options": ["The room is noisy.", "The train is delayed.", "The colour is too dark."], "answer": 0}, {"title": "Hair salon appointment", "audio": "Good morning. I would like to book an appointment for a haircut next Friday morning. Do you have any availability?", "transcript": "Good morning. I would like to book an appointment for a haircut next Friday morning. Do you have any availability?", "q": "What does the speaker want?", "options": ["A restaurant table.", "A hair salon appointment.", "A train ticket."], "answer": 1}, {"title": "Restaurant allergy", "audio": "I would like to book a table for two on Saturday at seven thirty. One person has a nut allergy. Could you confirm the reservation?", "transcript": "I would like to book a table for two on Saturday at seven thirty. One person has a nut allergy. Could you confirm the reservation?", "q": "What important information is mentioned?", "options": ["A nut allergy.", "A noisy room.", "A missed connection."], "answer": 0}, {"title": "Train delay", "audio": "My train is delayed and I am worried I will miss my connection. Could you rebook me on the next available train?", "transcript": "My train is delayed and I am worried I will miss my connection. Could you rebook me on the next available train?", "q": "What does the speaker ask for?", "options": ["A new haircut.", "A rebooking on the next train.", "A restaurant bill."], "answer": 1}, {"title": "Salon colour problem", "audio": "I had my hair coloured yesterday, but the colour is darker than I expected. Would it be possible to come back so you can have a look?", "transcript": "I had my hair coloured yesterday, but the colour is darker than I expected. Would it be possible to come back so you can have a look?", "q": "What is the problem?", "options": ["The colour is too dark.", "The room is too noisy.", "The train is cancelled."], "answer": 0}, {"title": "Taxi to hotel", "audio": "I would like to go to the Royal Hotel, please. Could you tell me approximately how much it will cost? Can I pay by card?", "transcript": "I would like to go to the Royal Hotel, please. Could you tell me approximately how much it will cost? Can I pay by card?", "q": "What does the speaker ask about?", "options": ["Price and card payment.", "Breakfast and room number.", "Hair colour and shampoo."], "answer": 0}, {"title": "Pharmacy advice", "audio": "Hello. I have a headache. Do you have something for pain? I do not have any allergies. How often should I take it?", "transcript": "Hello. I have a headache. Do you have something for pain? I do not have any allergies. How often should I take it?", "q": "Where is this situation likely happening?", "options": ["At a pharmacy.", "At a hair salon.", "At a train station."], "answer": 0}, {"title": "Compare hotels", "audio": "I prefer the second hotel because it is quieter and closer to the station. It is a little more expensive, but the location is better for me.", "transcript": "I prefer the second hotel because it is quieter and closer to the station. It is a little more expensive, but the location is better for me.", "q": "Why does the speaker prefer the second hotel?", "options": ["It is quieter and closer to the station.", "It has a hair salon.", "It is the cheapest option."], "answer": 0}], "writingMissions": [{"title": "Email: change an appointment", "prompt": "Write a short email to reschedule an appointment.", "model": "Hello,\n\nI am writing to reschedule my appointment on Tuesday at 10 am. Would Thursday afternoon be possible?\n\nThank you for your understanding.\nBest regards,\nKarine"}, {"title": "Email: hotel room problem", "prompt": "Write a polite email to ask for a quieter room.", "model": "Hello,\n\nI am staying in room [number]. Unfortunately, the room is quite noisy. Would it be possible to move to a quieter room, if available?\n\nThank you for your help.\nBest regards,\nKarine"}, {"title": "Email: salon colour follow-up", "prompt": "Write a polite message after a colour service that is too dark.", "model": "Hello,\n\nI had my hair coloured yesterday, but the result is darker than I expected. Would it be possible to come back so you can have a look and advise me?\n\nThank you for your help.\nBest regards,\nKarine"}, {"title": "Email: restaurant reservation", "prompt": "Write to book a table and mention an allergy.", "model": "Hello,\n\nI would like to book a table for two people on Saturday at 7:30 pm. Please note that one person has a nut allergy. Could you please confirm the reservation?\n\nThank you very much.\nBest regards,\nKarine"}, {"title": "Email: lost luggage", "prompt": "Write a short message to report lost luggage.", "model": "Hello,\n\nMy suitcase did not arrive after my flight. It is a medium black suitcase with a red tag. Could you please let me know what I should do next?\n\nBest regards,\nKarine"}, {"title": "Short paragraph: compare two hotels", "prompt": "Compare two hotel options and justify your choice.", "model": "I prefer the second hotel because it is quieter and closer to the station. It is a little more expensive, but the location is better for me. I think it is the best option."}]};
function $(s,r){return (r||document).querySelector(s)}
function $all(s,r){return Array.from((r||document).querySelectorAll(s))}
function shuffle(arr){let a=arr.slice();for(let i=a.length-1;i>0;i--){let j=Math.floor(Math.random()*(i+1));[a[i],a[j]]=[a[j],a[i]]}return a}
let state={activeTopicId:DATA.topics[0].id,activeQuiz:null,activeListening:0,score:0,completed:new Set(),timer:45,timerLeft:45,timerId:null};
const speechSupported="speechSynthesis" in window && "SpeechSynthesisUtterance" in window;
function stopSpeech(){if(speechSupported) window.speechSynthesis.cancel()}
function speak(text){if(!speechSupported){alert("Text-to-speech is not available in this browser.");return} stopSpeech(); const u=new SpeechSynthesisUtterance(String(text||"")); u.lang=$("#accent").value||"en-GB"; u.rate=.95; window.speechSynthesis.speak(u)}
function addScore(key,pts=1){if(!state.completed.has(key)){state.completed.add(key);state.score+=pts;renderScore()}}
function maxScore(){return DATA.grammar.reduce((s,g)=>s+g.ex.length,0)+40}
function renderScore(){$("#scoreTop").textContent=state.score;$("#scoreBottom").textContent=state.score;$("#maxTop").textContent=maxScore();$("#maxBottom").textContent=maxScore();$("#completedTop").textContent=state.completed.size}
function activeTopic(){return DATA.topics.find(t=>t.id===state.activeTopicId)||DATA.topics[0]}
function renderTopics(){const grid=$("#topicGrid");const search=($("#search").value||"").toLowerCase();const filter=$(".filters .chip.is-on").dataset.filter;grid.innerHTML="";DATA.topics.filter(t=>{const text=(t.title+" "+t.desc+" "+t.tags.join(" ")).toLowerCase();return (!search||text.includes(search))&&(filter==="all"||t.tags.includes(filter))}).forEach(t=>{const card=document.createElement("article");card.className="topic"+(t.id===state.activeTopicId?" is-active":"");card.innerHTML=`<div class="topic__t">${t.title}</div><div class="topic__d">${t.desc}</div><div class="tags">${t.tags.map(x=>`<span class="tag">${x}</span>`).join("")}</div><div class="pill tiny">⏱ ${t.recommended}s speaking</div>`;card.addEventListener("click",()=>selectTopic(t.id));grid.appendChild(card)})}
function selectTopic(id){state.activeTopicId=id;renderTopics();renderWorkshop();renderSpeaking();renderVocab()}
function renderDialogue(t){$("#dialogueWrap").innerHTML=`<div class="dialogue">${t.dialogue.map(l=>`<div class="line"><div class="speaker">${l[0]}</div><div><div class="text">${l[1]}</div><div class="fr">${l[2]}</div></div><button class="iconbtn" data-say="${encodeURIComponent(l[1])}">🔊</button></div>`).join("")}</div>`;$all("#dialogueWrap [data-say]").forEach(b=>b.addEventListener("click",()=>speak(decodeURIComponent(b.dataset.say))));}
function renderEmail(t){$("#emailWrap").innerHTML=`<div class="email"><div class="subj">${t.writing.subject}</div><pre>${t.writing.body}</pre></div>`}
function renderQuiz(t){const q=shuffle(t.quizBank)[0];state.activeQuiz=q;$("#quizPrompt").innerHTML=`<strong>${q[0]}</strong><br>${q[1]}`;$("#quizOptions").innerHTML=q[2].map((opt,i)=>`<label class="opt"><input type="radio" name="quizOpt" value="${i}"><span>${opt}</span></label>`).join("");$("#quizFeedback").className="feedback";$("#quizFeedback").textContent="";$("#quizModel").classList.add("hidden");$("#quizModel").innerHTML=`<strong>Model answer:</strong><p>${q[2][q[3]]}</p><p class="muted">${q[4]}</p>`}
function renderBuilder(t){const pool=$("#blockPool"),lane=$("#answerLane");pool.innerHTML="";lane.innerHTML="";$("#builderFeedback").className="feedback";$("#builderFeedback").textContent="";$("#builderModel").classList.add("hidden");$("#builderModel").innerHTML=`<strong>Model response:</strong><ol>${t.builderModel.map(x=>`<li>${x}</li>`).join("")}</ol>`;shuffle(t.builderModel).forEach(txt=>{const div=document.createElement("div");div.className="block";div.innerHTML=`<div><div class="block__text">${txt}</div><div class="block__meta">Answer block</div></div><button class="iconbtn add">➕ Add</button>`;div.querySelector(".add").addEventListener("click",()=>{const li=document.createElement("li");li.className="answeritem";li.dataset.text=txt;li.innerHTML=`<div class="answeritem__text">${txt}</div><button class="iconbtn remove">✕</button>`;li.querySelector(".remove").addEventListener("click",()=>li.remove());lane.appendChild(li)});pool.appendChild(div)})}
function renderDrills(t){$("#extraDrills").innerHTML=t.drills.map((d,i)=>`<article class="drill"><div class="pill tiny">Prompt ${i+1}</div><p>${d}</p><button class="iconbtn" data-say="${encodeURIComponent(d)}">🔊 Prompt</button></article>`).join("");$("#drillModels").innerHTML=`<strong>Model responses:</strong><ol>${t.models.map(m=>`<li>${m}</li>`).join("")}</ol>`;$all("#extraDrills [data-say]").forEach(b=>b.addEventListener("click",()=>speak(decodeURIComponent(b.dataset.say))))}
function renderWorkshop(){const t=activeTopic();$("#activeTopicPill").textContent="Topic: "+t.title;renderDialogue(t);renderEmail(t);renderQuiz(t);renderBuilder(t);renderDrills(t);renderSpeaking()}
function renderGrammar(){const wrap=$("#grammarModules");const filter=$("#grammarSelect").value;wrap.innerHTML="";DATA.grammar.filter(g=>filter==="all"||g.id===filter).forEach(g=>{const mod=document.createElement("article");mod.className="gmodule";mod.innerHTML=`<h3>${g.title}</h3><div class="rule">${g.rule}</div><div class="examples">${g.examples.map(e=>`<div class="example">✅ ${e}</div>`).join("")}</div><div class="gex"></div>`;const exwrap=mod.querySelector(".gex");g.ex.forEach((ex,ei)=>{const id=`g-${g.id}-${ei}`;const box=document.createElement("div");box.className="qbox";box.innerHTML=`<p>${ex[0]}</p><div class="options">${ex[2].map(o=>`<label class="opt"><input type="radio" name="${id}" value="${o}"><span>${o}</span></label>`).join("")}</div><button class="btn checkGrammar" type="button">Show if correct</button><div class="feedback"></div>`;box.querySelector(".checkGrammar").addEventListener("click",()=>{const chosen=box.querySelector(`input[name="${id}"]:checked`);const fb=box.querySelector(".feedback");if(!chosen){fb.className="feedback warn";fb.textContent="Choose an answer first.";return}if(chosen.value===ex[1]){fb.className="feedback good";fb.textContent="✅ Correct. "+g.rule;addScore(id)}else{fb.className="feedback bad";fb.textContent=`❌ Not yet. Correct answer: ${ex[1]}. ${g.rule}`}});exwrap.appendChild(box)});wrap.appendChild(mod)})}
function renderListening(){const l=DATA.listenings[state.activeListening%DATA.listenings.length];$("#listeningBox").innerHTML=`<div class="pill tiny">${l.title}</div><p class="qtext">${l.q}</p><div class="options">${l.options.map((o,i)=>`<label class="opt"><input type="radio" name="listeningOpt" value="${i}"><span>${o}</span></label>`).join("")}</div>`;$("#transcriptBox").textContent=l.transcript;$("#transcriptBox").classList.add("hidden");$("#listeningFeedback").className="feedback";$("#listeningFeedback").textContent=""}
function renderSpeaking(){const t=activeTopic();$("#speakingPrompt").textContent=t.speakPrompt;$("#speakingModel").classList.add("hidden");$("#speakingChecklist").classList.add("hidden");$("#speakingModel").innerHTML=`<strong>Model response:</strong><p>${t.builderModel.join(" ")}</p>`;$("#speakingChecklist").innerHTML=`<strong>✅ Your answer is correct if it includes:</strong><ul><li>a polite opening</li><li>the situation or problem</li><li>a precise request</li><li>one useful detail: time, place, reason, preference</li><li>a thank you or closing</li></ul>`}
function renderVocab(){const grid=$("#flashGrid");const filter=$("#vocabFilter").value;const words=shuffle(DATA.vocab.filter(v=>filter==="all"||v[0]===filter));grid.innerHTML=words.map(v=>`<article class="flash"><div class="flash__icon">${v[1]}</div><div class="flash__front">${v[2]}</div><div class="flash__back"><strong>FR:</strong> ${v[3]}<br><strong>Example:</strong> ${v[4]}</div><div class="flash__cat"><span class="tag">${v[0]}</span></div><button class="iconbtn sayVocab" data-say="${encodeURIComponent(v[4])}">🔊</button></article>`).join("");$all(".sayVocab").forEach(b=>b.addEventListener("click",e=>{e.stopPropagation();speak(decodeURIComponent(b.dataset.say))}));}
function renderWriting(){$("#writingGrid").innerHTML=DATA.writingMissions.map((w,i)=>`<article class="writecard"><h3>${w.title}</h3><p class="muted">${w.prompt}</p><button class="btn showWrite" data-i="${i}">Show model response</button><button class="btn btn--ghost listenWrite" data-i="${i}">🔊 Listen</button><pre class="email hidden" id="writeModel${i}">${w.model}</pre></article>`).join("");$all(".showWrite").forEach(b=>b.addEventListener("click",()=>$("#writeModel"+b.dataset.i).classList.toggle("hidden")));$all(".listenWrite").forEach(b=>b.addEventListener("click",()=>speak(DATA.writingMissions[Number(b.dataset.i)].model)))}
function setupEvents(){$("#btnStopSpeech").addEventListener("click",stopSpeech);$("#btnPrint").addEventListener("click",()=>window.print());$("#btnResetAll").addEventListener("click",()=>{state.score=0;state.completed=new Set();renderScore();renderGrammar();renderWorkshop();renderListening()});$all("[data-scroll]").forEach(b=>b.addEventListener("click",()=>$(b.dataset.scroll).scrollIntoView({behavior:"smooth"})));$("#search").addEventListener("input",renderTopics);$all(".filters .chip").forEach(c=>c.addEventListener("click",()=>{$all(".filters .chip").forEach(x=>x.classList.remove("is-on"));c.classList.add("is-on");renderTopics()}));$("#grammarSelect").addEventListener("change",renderGrammar);$("#vocabFilter").addEventListener("change",renderVocab);$("#btnShuffleVocab").addEventListener("click",renderVocab);
$("#btnListenDialogue").addEventListener("click",()=>speak(activeTopic().dialogue.map(l=>l[1]).join(" ")));$("#btnToggleDialogue").addEventListener("click",()=>$("#dialogueWrap").classList.toggle("hidden"));$("#btnCopyEmail").addEventListener("click",()=>navigator.clipboard&&navigator.clipboard.writeText(activeTopic().writing.subject+"\n\n"+activeTopic().writing.body));$("#btnListenEmail").addEventListener("click",()=>speak(activeTopic().writing.subject+". "+activeTopic().writing.body));$("#btnToggleEmail").addEventListener("click",()=>$("#emailWrap").classList.toggle("hidden"));
$("#btnNewQuiz").addEventListener("click",()=>renderQuiz(activeTopic()));$("#btnListenQuiz").addEventListener("click",()=>speak(state.activeQuiz?state.activeQuiz[1]:activeTopic().speakPrompt));$("#btnShowQuizModel").addEventListener("click",()=>$("#quizModel").classList.toggle("hidden"));$("#btnCheckQuiz").addEventListener("click",()=>{const chosen=$("#quizOptions input:checked");const fb=$("#quizFeedback");if(!chosen){fb.className="feedback warn";fb.textContent="Choose an answer first.";return}const idx=Number(chosen.value),q=state.activeQuiz;if(idx===q[3]){fb.className="feedback good";fb.textContent="✅ Correct. "+q[4];addScore("quiz-"+activeTopic().id+"-"+q[1])}else{fb.className="feedback bad";fb.textContent="❌ Not correct yet. Correct answer: "+q[2][q[3]]+". "+q[4]}});$("#btnResetQuiz").addEventListener("click",()=>renderQuiz(activeTopic()));
$("#btnResetBuilder").addEventListener("click",()=>renderBuilder(activeTopic()));$("#btnListenBuilder").addEventListener("click",()=>speak(activeTopic().builderModel.join(" ")));$("#btnShowBuilderModel").addEventListener("click",()=>$("#builderModel").classList.toggle("hidden"));$("#btnCheckBuilder").addEventListener("click",()=>{const chosen=$all("#answerLane .answeritem").map(x=>x.dataset.text);const model=activeTopic().builderModel;const fb=$("#builderFeedback");if(chosen.length!==model.length){fb.className="feedback warn";fb.textContent="Add all the blocks first.";return}const ok=chosen.every((x,i)=>x===model[i]);if(ok){fb.className="feedback good";fb.textContent="✅ Correct order. This answer is complete and exam-ready.";addScore("builder-"+activeTopic().id)}else{fb.className="feedback bad";fb.textContent="❌ Not yet. Click “Show model” to compare."}});
$("#btnShowDrillModel").addEventListener("click",()=>$("#drillModels").classList.toggle("hidden"));$("#btnListenDrills").addEventListener("click",()=>speak(activeTopic().models.join(" ")));
$("#btnNewListening").addEventListener("click",()=>{state.activeListening++;renderListening()});$("#btnListenListening").addEventListener("click",()=>speak(DATA.listenings[state.activeListening%DATA.listenings.length].audio));$("#btnToggleTranscript").addEventListener("click",()=>$("#transcriptBox").classList.toggle("hidden"));$("#btnCheckListening").addEventListener("click",()=>{const l=DATA.listenings[state.activeListening%DATA.listenings.length];const chosen=$("#listeningBox input:checked");const fb=$("#listeningFeedback");if(!chosen){fb.className="feedback warn";fb.textContent="Choose an answer first.";return}if(Number(chosen.value)===l.answer){fb.className="feedback good";fb.textContent="✅ Correct listening answer.";addScore("listening-"+state.activeListening)}else{fb.className="feedback bad";fb.textContent="❌ Not correct. Correct answer: "+l.options[l.answer]}});
$("#btnNewSpeaking").addEventListener("click",()=>{const idx=DATA.topics.findIndex(t=>t.id===state.activeTopicId);selectTopic(DATA.topics[(idx+1)%DATA.topics.length].id)});$("#btnListenSpeaking").addEventListener("click",()=>speak(activeTopic().speakPrompt));$("#btnShowSpeakingModel").addEventListener("click",()=>$("#speakingModel").classList.toggle("hidden"));$("#btnListenSpeakingModel").addEventListener("click",()=>speak(activeTopic().builderModel.join(" ")));$("#btnShowSpeakingCheck").addEventListener("click",()=>{$("#speakingChecklist").classList.toggle("hidden");addScore("speak-check-"+activeTopic().id)});
$all(".chipbtn").forEach(b=>b.addEventListener("click",()=>{state.timer=Number(b.dataset.time);state.timerLeft=state.timer;$all(".chipbtn").forEach(x=>x.classList.remove("is-on"));b.classList.add("is-on");$("#timerNum").textContent=state.timerLeft}));$("#btnStartTimer").addEventListener("click",()=>{clearInterval(state.timerId);state.timerId=setInterval(()=>{state.timerLeft--;$("#timerNum").textContent=state.timerLeft;if(state.timerLeft<=0){clearInterval(state.timerId);speak("Time is up.")}},1000)});$("#btnStopTimer").addEventListener("click",()=>clearInterval(state.timerId));$("#btnResetTimer").addEventListener("click",()=>{clearInterval(state.timerId);state.timerLeft=state.timer;$("#timerNum").textContent=state.timerLeft})}
function init(){renderScore();setupEvents();renderTopics();renderGrammar();renderWorkshop();renderListening();renderVocab();renderWriting()}
document.addEventListener("DOMContentLoaded",init);
})();
